  { json: { url: 'https://mocc.gov.pk/SiteImage/Misc/files/Pakistan%20Climate%20Change%20Act%202017.pdf', org: 'Ministry of Climate Change Pakistan', geo_scope: 'pakistan', sector_tags: ['transport','buildings','waste','industry','energy'], framework_tags: ['paris'] } },
  { json: { url: 'https://www.c40knowledgehub.org/s/article/Mayors-Guide-to-EV-Adoption', org: 'C40 Cities', geo_scope: 'global', sector_tags: ['transport'], framework_tags: ['c40'] } },
  { json: { url: 'https://www.iea.org/reports/transport', org: 'IEA', geo_scope: 'global', sector_tags: ['transport'], framework_tags: ['iea'] } },
  { json: { url: 'https://www.ipcc.ch/report/ar6/wg3/chapter/chapter-10/', org: 'IPCC AR6 WG3 Ch.10', geo_scope: 'global', sector_tags: ['transport'], framework_tags: ['ipcc-ar6'] } },
  { json: { url: 'https://www.ipcc.ch/report/ar6/wg3/chapter/chapter-9/', org: 'IPCC AR6 WG3 Ch.9', geo_scope: 'global', sector_tags: ['buildings'], framework_tags: ['ipcc-ar6'] } },
  { json: { url: 'https://www.ipcc.ch/report/ar6/wg3/chapter/chapter-11/', org: 'IPCC AR6 WG3 Ch.11', geo_scope: 'global', sector_tags: ['waste','industry'], framework_tags: ['ipcc-ar6'] } }
  // Add more sources as needed.
];

// Detect PDF vs HTML by content-type or magic bytes, extract text, chunk.
const meta = $('Iterate sources').first().json;
const raw = $input.first().json.data || $input.first().json.body || '';
const headers = $input.first().json.headers || {};
const ct = (headers['content-type'] || '').toLowerCase();

let text = '';
if (ct.includes('pdf') || raw.startsWith('%PDF')) {
  // For PDFs you typically want the built-in Extract from File node. For
  // simplicity here we stub it — replace this branch with a real PDF extractor.
  text = '[PDF content — replace this branch with the Extract-from-File node feeding into this code node]';
} else {
  // Naive HTML→text: strip tags, collapse whitespace.
  text = raw
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/\s+/g, ' ')
    .trim();
}

if (!text || text.length < 200) return [];

// Recursive char chunker — ~800 tokens (~3200 chars) with 400 overlap.
const chunkSize = 3200;
const overlap = 400;
const chunks = [];
for (let i = 0; i < text.length; i += chunkSize - overlap) {
  const slice = text.slice(i, i + chunkSize).trim();
  if (slice.length < 200) continue;
  chunks.push(slice);
}

const crypto = require('crypto');
const title = (text.match(/^.{0,150}/) || ['untitled'])[0].slice(0, 150);

return chunks.map((chunk, idx) => ({ json: {
  source_url: meta.url,
  source_title: title,
  source_org: meta.org,
  geo_scope: meta.geo_scope,
  sector_tags: meta.sector_tags,
  framework_tags: meta.framework_tags,
  chunk_index: idx,
  chunk_text: chunk,
  content_hash: crypto.createHash('sha256').update(chunk).digest('hex'),
}}));
